import{_ as t,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Random Image API এবং Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Other/random-image-api-and-public-gallery.md","filePath":"bn-BD/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"bn-BD/Other/random-image-api-and-public-gallery.md"};function o(l,e,s,c,n,p){return a(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="random-image-api-এবং-public-gallery" tabindex="-1">Random Image API এবং Public Gallery <a class="header-anchor" href="#random-image-api-এবং-public-gallery" aria-label="Permalink to &quot;Random Image API এবং Public Gallery&quot;">​</a></h1><p>দুটি feature-ই এখানে configure করা হয়:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API selected directories থেকে একটি random file return করে। Site backgrounds, avatar rotation বা external pages থেকে random image calls-এর জন্য এটি useful।</p><p>Enable করার পর ব্যবহার করুন:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td><code>/random</code> endpoint on বা off করে। Disabled থাকলে access forbidden।</td></tr><tr><td>Directories</td><td>Random API কোন directories ব্যবহার করতে পারবে তা limit করে। এখানে না থাকা directories API ব্যবহার করতে পারবে না।</td></tr><tr><td>Call demo</td><td>Copy করার জন্য random API links generate করে।</td></tr></tbody></table><p>Multiple directories select করা যায়। যেমন, শুধু <code>/landscape/</code> এবং <code>/portrait/</code> allowed হলে random API শুধু ওই directories এবং subdirectories থেকে files নিতে পারবে।</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Random directory specify করে।</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Media type specify করে। <code>image</code>, <code>video</code>, <code>audio</code> বা comma-separated combinations ব্যবহার করুন।</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Image orientation filter করে। <code>portrait</code>, <code>landscape</code> বা <code>auto</code> ব্যবহার করুন।</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Return format। Empty মানে redirect, <code>url</code> plain text URL return করে, <code>json</code> JSON return করে।</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td><code>type=url</code>-এর সঙ্গে full URL return করতে ব্যবহৃত হয়।</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Age rating দিয়ে filter করে।</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>এই tags থাকা files-ই return করে।</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>এই tags থাকা files exclude করে।</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p><code>type</code> না থাকলে API সরাসরি random file URL-এ redirect করে।</p><p><code>type=url</code> থাকলে text URL return করে।</p><p><code>type=json</code> থাকলে file information return করে, যার মধ্যে file URL, file ID, file name, file type, tags, rating এবং related metadata থাকে।</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>Random Image API public access rules follow করে:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>শুধু allowed directories-এর files select হতে পারে।</td></tr><tr><td>Blocklist</td><td>Blocklisted files random pool থেকে excluded হয়।</td></tr><tr><td>Allowlist mode</td><td>Enabled হলে শুধু public access-এর জন্য allowed files return হয়।</td></tr><tr><td>Age rating</td><td>R12, R16, R18 এবং similar content current access mode দিয়ে filter হয়।</td></tr></tbody></table><p>Filtering-এর পর কোনো file match না করলে API no matching result return করে।</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Speed বাড়াতে Random Image API directory candidate pools cache করে।</p><p>Files বদলালে ImgBed directory cache version update করে, এবং পরের requests candidate pool rebuild করে। Repeated queries এড়াতে empty directories সামান্য সময় cache করা হয়।</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>Public gallery visitors-কে দেখাতে চান এমন directories-এর জন্য read-only public browsing page দেয়।</p><p>Enable করার পর visitors খুলতে পারবে:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>Public gallery on বা off করে। Disabled হলে visitors browse করতে পারে না।</td></tr><tr><td>Image loading mode</td><td>Previews original images ব্যবহার করবে নাকি thumbnails, তা control করে।</td></tr><tr><td>Open directories</td><td>Visitors কোন directories access করতে পারবে তা set করে।</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>Visitor page original files directly load করে।</td></tr><tr><td>Thumbnail</td><td>Faster loading-এর জন্য visitor page thumbnails prefer করে।</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories ঠিক করে visitors কী দেখতে পারবে।</p><p>Example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors তখন access করতে পারবে:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories-ও open করা যায়, যেমন <code>/2026/lucky/</code>। Open নয় এমন directories visitors-এর জন্য blocked থাকে।</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>Open directories-এর files এবং subdirectories দেখুন।</td></tr><tr><td>Search</td><td>File name, file ID বা tags দিয়ে search করুন।</td></tr><tr><td>Type filter</td><td>Images, videos, audio বা other files filter করুন।</td></tr><tr><td>Tag filter</td><td>Selected tags include বা exclude করুন।</td></tr><tr><td>Orientation filter</td><td>Landscape বা portrait images filter করুন।</td></tr><tr><td>Time filter</td><td>Upload time range দিয়ে filter করুন।</td></tr><tr><td>Extension filter</td><td>File extension দিয়ে filter করুন।</td></tr><tr><td>Copy link</td><td>File access links copy করুন।</td></tr><tr><td>Media preview</td><td>Visitor page-এ images, videos এবং audio দেখুন বা play করুন।</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>Public gallery-ও public access rules follow করে:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>শুধু allowed directories দেখায়।</td></tr><tr><td>Access mode</td><td>Content current age-rating access mode দিয়ে filter হয়।</td></tr><tr><td>Allowlist mode</td><td>Enabled হলে শুধু public access-এর জন্য allowed files দেখায়।</td></tr><tr><td>Blocklist</td><td>Blocklisted files hidden থাকে।</td></tr></tbody></table>`,43)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
